mapper.select:
WITH dept_match AS (
    SELECT departId AS rootId, departId, name, parentId, 0 AS lvl
    FROM VX_DepartmentList
    WHERE name = #{name}
    UNION ALL
    SELECT m.rootId, d.departId, d.name, d.parentId, m.lvl + 1
    FROM VX_DepartmentList d
    INNER JOIN dept_match m ON d.departId = m.parentId
    WHERE m.lvl <


            ${ancestorNames.size()}

        0

    AND d.name =



                WHEN ${idx} THEN #{aName}


        #{name}

)
SELECT rootId FROM dept_match
WHERE lvl =

    ${ancestorNames.size()}
    0

OPTION (MAXRECURSION 10)
